package controller

import (
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"fmt"
	"net/http"
	"os"
	"runtime"
	"runtime/pprof"
	"strconv"
	"time"

	json "github.com/json-iterator/go"
)

const (
	defaultProfileDuration = 30
	// https://go.dev/src/runtime/pprof/pprof.go#L810
	// Default profiling rate is 100 Hz, and suggested max is 500 Hz
	defaultProfileRate       = 100
	maxProfileRate           = 500
	cpuProfileFileNamePrefix = "cpu_profile_"
	memProfileFileNamePrefix = "mem_profile_"
)

// fileSystem defines the interface for file system operations.
type fileSystem interface {
	MkdirAll(path string, perm os.FileMode) error
	Create(name string) (*os.File, error)
	DirectoryExists(path string) (bool, error)
}

type profilerOutput struct {
	CpuProfileName string `json:"cpu_profile_name,omitempty"`
	MemProfileName string `json:"mem_profile_name,omitempty"`
	Message        string `json:"message,omitempty"`
}

// profiler defines the interface for profiling operations.
type profiler interface {
	StartCPUProfile(w *os.File) error
	StopCPUProfile()
	WriteHeapProfile(w *os.File) error
}

type oSFileSystem struct{}

func (oSFileSystem) MkdirAll(path string, perm os.FileMode) error {
	return os.MkdirAll(path, perm)
}

func (oSFileSystem) Create(name string) (*os.File, error) {
	return os.Create(name)
}

func (oSFileSystem) DirectoryExists(path string) (bool, error) {
	info, err := os.Stat(path)
	if err != nil && os.IsNotExist(err) {
		return false, nil
	}

	if err != nil {
		return false, err
	}

	return info.IsDir(), nil
}

// pprofProfiler implements the Profiler interface using the runtime/pprof package.
type pprofProfiler struct{}

func (pprofProfiler) StartCPUProfile(w *os.File) error {
	return pprof.StartCPUProfile(w)
}

func (pprofProfiler) StopCPUProfile() {
	pprof.StopCPUProfile()
}

func (pprofProfiler) WriteHeapProfile(w *os.File) error {
	return pprof.WriteHeapProfile(w)
}

func StartApplicationProfiling(w http.ResponseWriter, r *http.Request, tempFolderPath string) {
	profileApplication(&oSFileSystem{}, &pprofProfiler{}, w, r, tempFolderPath)
}

func profileApplication(
	fs fileSystem,
	profiler profiler,
	w http.ResponseWriter,
	r *http.Request,
	tempFolderPath string,
) {
	// Parse the duration query parameter, default to 30 seconds if not provided
	// or invalid
	logContext := log.NewEmptyLogContext(0)
	durationStr := r.URL.Query().Get("duration")
	profileDuration, err := strconv.Atoi(durationStr)
	if err != nil || profileDuration <= 0 {
		profileDuration = defaultProfileDuration
	}

	// Generate filenames with timestamp
	// check temp directory exists
	exists, err := fs.DirectoryExists(tempFolderPath)
	if err != nil {
		log.Errorw(
			logContext,
			fmt.Sprintf("Unable to access temp directory: %s", tempFolderPath),
			log.ErrorKey,
			err,
		)

		http.Error(
			w,
			fmt.Sprintf("Unable to access temp directory: %s", tempFolderPath),
			http.StatusInternalServerError,
		)
		return
	}

	if !exists {
		if err = fs.MkdirAll(tempFolderPath, 0755); err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf("Failed to create temp directory: %s", tempFolderPath),
				log.ErrorKey,
				err,
			)

			http.Error(
				w,
				fmt.Sprintf("Failed to create temp directory: %s", tempFolderPath),
				http.StatusInternalServerError,
			)
			return
		}
	}

	timestamp := time.Now().Format("20060102-150405") // YYYYMMDD-HHMMSS format
	cpuProfileFileName := fmt.Sprintf("%s/%s%s.pprof", tempFolderPath, cpuProfileFileNamePrefix, timestamp)
	memProfileFileName := fmt.Sprintf("%s/%s%s.pprof", tempFolderPath, memProfileFileNamePrefix, timestamp)

	// Start CPU profiling
	cpuFile, err := fs.Create(cpuProfileFileName)
	if err != nil {
		log.Errorw(
			logContext,
			fmt.Sprintf("Could not create CPU profile file: %s", cpuProfileFileName),
			log.ErrorKey,
			err,
		)

		http.Error(
			w,
			fmt.Sprintf("Could not create CPU profile file: %s", cpuProfileFileName),
			http.StatusInternalServerError,
		)
		return
	}

	defer func() {
		err := cpuFile.Close()
		if err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf("Error occurred while closing CPU profile file: %s", cpuProfileFileName),
				log.ErrorKey,
				err,
			)
		}
	}()

	setProfileRate(r)

	if err := profiler.StartCPUProfile(cpuFile); err != nil {
		log.Errorw(
			logContext,
			"Could not start CPU profile",
			log.ErrorKey,
			err,
		)

		http.Error(w, "Could not start CPU profile", http.StatusInternalServerError)
		return
	}

	time.AfterFunc(time.Duration(profileDuration)*time.Second, func() {
		profiler.StopCPUProfile()
		// Write heap profile
		heapFile, err := fs.Create(memProfileFileName)
		if err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf("Could not create heap profile file: %s", memProfileFileName),
				log.ErrorKey,
				err,
			)

			return
		}

		defer func() {
			err := heapFile.Close()

			if err != nil {
				log.Errorw(
					logContext,
					fmt.Sprintf("Error occurred while closing heap profile file: %s", memProfileFileName),
					log.ErrorKey,
					err,
				)
			}
		}()

		if err := profiler.WriteHeapProfile(heapFile); err != nil {
			log.Errorw(
				logContext,
				fmt.Sprintf("Could not write heap profile: %s", memProfileFileName),
				log.ErrorKey,
				err,
			)

			return
		}

		log.Infof(
			logContext,
			"CPU and memory profiles have been written to '%s' and '%s' respectively.",
			cpuProfileFileName,
			memProfileFileName,
		)
	})

	output := profilerOutput{
		CpuProfileName: cpuProfileFileName,
		MemProfileName: memProfileFileName,
		Message: fmt.Sprintf(
			"Profiling started. CPU and heap profiles will be available in '%s' after %d seconds.",
			tempFolderPath,
			profileDuration,
		),
	}

	jsonOutput, err := json.Marshal(output)
	if err != nil {
		log.Errorw(
			logContext,
			"Failed to marshal profilerOutput to JSON",
			log.ErrorKey,
			err,
			"profiler_output",
			output,
		)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	// Respond to the request
	w.WriteHeader(http.StatusOK)
	w.Write(jsonOutput)
}

func setProfileRate(r *http.Request) {
	// Parse the profile rate from the query string
	profileRateStr := r.URL.Query().Get("rate")
	profileRate, err := strconv.Atoi(profileRateStr)

	if err != nil || profileRate <= 0 {
		profileRate = defaultProfileRate // Use default rate if not specified or on error
	}

	if profileRate > maxProfileRate {
		profileRate = maxProfileRate
	}

	// Only set the CPU profile rate if it differs from the default
	if profileRate != defaultProfileRate {
		runtime.SetCPUProfileRate(profileRate)
	}
}
