		scriptsDir            string
		telemetryConfigPath   string
		startUpApp            string
	)

	logContext := log.NewLogContextWithCorrelationIds(uuid.NewString())

	logContextFunc := func() *log.Context {
		return logContext
	}

	defer errorHandling.LogPanicAndExit(logContextFunc)

	flag.StringVar(&rootDir, "rootDir", "./", "Root directory where OpenSearch files are located.")
	flag.StringVar(
		&mappingConfigPath,
		"mappingConfigPath",
		schemaMapping.DefaultMappingConfigPath,
		"Path to the schema mapping configuration file.",
	)
	flag.StringVar(
		&indexConfigFilePath,
		"indexConfigFilePath",
		opensearchInternal.DefaultIndexConfigFilePath,
		"Path to the index config file.",
	)
	flag.StringVar(
		&indexDependenciesPath,
		"indexDependenciesPath",
		"configs/"+dependencies.DefaultDependenciesFilename,
		"Path to the index dependencies configuration file.",
	)
	flag.StringVar(
		&scriptsDir,
		"scripts",
		opensearchInternal.DefaultSchemaRootDirPath,
		"Path to indices, templated-scripts, and queries.",
	)
	flag.StringVar(
		&telemetryConfigPath,
		"telemetryConfigPath",
		"configs/telemetry.yaml",
		"Path to the telemetry configuration file.",
	)
	flag.StringVar(
		&startUpApp,
		"startup",
		ingestApp,
		"The startup application. Default ingest.",
	)
	flag.Parse()

	// Only load exact environment files.
	err := godotenv.Load(projectPaths.DotEnv)
	errorHandling.HandleWarning(logContext, errors.Wrap(err, "main.init"))

	// initialize logger
	log.SetLevel(env.LookupValue(log.LogLevelEnvKey, log.InfoLevel))
	log.InitializeLogger(false, map[string]string{pkg.StartUpKey: startUpApp})
	helpers.SetLogLevelsFromFeatureFlags()

	var memStats *runtime.MemStats = &runtime.MemStats{}
	runtime.ReadMemStats(memStats)
	log.Infow(
		logContext,
		fmt.Sprintf(
			"Omnissa Gumdrop Ingestion v%s, (c) %v Omnissa, LLC. All rights reserved.",
