			time.Now().UTC().Year(),
		),
		log.SupportedPublicSchemaVersionKey, version.SchemaVersion,
		"cpus", runtime.NumCPU(),
		"mem_stats", memStats,
	)

	go func() {
		errorHandling.HandleError(logContextFunc, http.ListenAndServe("localhost:6060", nil))
	}()

	kafkaClientIdPrefix := "gumdrop-ingestion"

	switch startUpApp {
	case fanOutApp:
		kafkaClientIdPrefix = "gumdrop-ingestion-fan-out"
	case recoveryApp:
