		uemRemediationApiClient = uemApiClient.NewUemRemediationApiClient(
			logContext,
			httpClient,
			transientErrorRetryClient,
			env.GetValue(logContext, pkg.TokenServiceUrlEnv),
			accessTokenProvider,
			&uemApiClient.UemRemediationApiClientConfig{
				UserAgent: fmt.Sprintf(
					"%s/%s (env=%s; ldd=%s; alloc_name=%s; alloc_id=%s)",
					version.ServiceName,
					version.Version,
					env.LookupValue(pkg.DataCenterNameEnv, ""),
					env.LookupValue(pkg.DeploymentNameEnv, ""),
					env.LookupValue(pkg.AllocationNameEnv, ""),
					env.LookupValue(pkg.AllocationIdEnv, ""),
				),
			},
		)
		ignoreDriftDetection = true
		remediationRequestEmitter = emitter.NewRemediationRequestEmitter(
			transientErrorRetryClient,
			uemRemediationApiClient,
			auditLogBatchSize,
		)
	}

	startUp = startup.NewIngestionStartup(
		logContext, &startup.Parameter{
			StartUp:                   startUpApp,
			RootDir:                   rootDir,
			ScriptRootDir:             scriptsDir,
			KafkaBrokers:              kafkaBrokers,
			KafkaConsumerTopics:       kafkaTopics,
			KafkaVersion:              kafkaVersion,
			BatchPartitionCount:       batchPartitionCount,
			BatchSize:                 batchSize,
			BatchDocsThreshold:        batchDocsThreshold,
			AuditLogBatchSize:         auditLogBatchSize,
			ClientId:                  kafkaClientId,
			MappingConfigPath:         mappingConfigPath,
			IndexDependenciesPath:     indexDependenciesPath,
			IndexConfigFilePath:       indexConfigFilePath,
			Refresh:                   refresh,
			KafkaConnectionMaxRetry:   maxRetry,
			QueueTimeout:              time.Duration(queueFlushTimeout) * time.Millisecond,
			TelemetryConfigPath:       telemetryConfigPath,
			DLQKafkaTopics:            dlqKafkaTopics,
			DLQClientId:               kafkaClientId + "-dlq",
			EnableConsumer:            true,
			MainApp:                   true,
			UpdateByQueryScrollSize:   updateByQueryScrollSize,
			UpdateByQuerySlices:       updateByQuerySlices,
			FanOutKafkaTopics:         fanOutKafkaTopic,
			FanOutClientId:            fanOutKafkaClientId,
			ProcessOnlyFanOut:         processOnlyFanOut,
			ApiRouteBasePath:          apiBasePath,
			BatchPartitioner:          batchPartitioner,
			MessageFilterCtor:         messageFilterCtor,
			MessageProcessorCtor:      messageProcessorCtor,
			UemRemediationApiClient:   uemRemediationApiClient,
			RemediationRequestEmitter: remediationRequestEmitter,
			IgnoreDriftDetection:      ignoreDriftDetection,
		},
	)
}

func getUpdateByQuerySlicesParameter() interface{} {
	// The slice parameter is an optional integer, which indicates the number of
	// slices the update by query task should be divided into. It defaults to 1
	// when no value is provided, meaning the task isn’t sliced into subtasks.
	// Setting slices to "auto" chooses a reasonable number for most data
	// streams and indices.
	// We will accept either auto, or a number.
	const auto = "auto"

	content := env.LookupNullableValue("UPDATE_BY_QUERY_SLICES", nil)
	if content == nil {
		return nil
	}

	if *content == auto {
		return auto
	}

	// it should be a number then
	value, err := strconv.Atoi(*content)
	if err != nil {
		// let the server default it to 1
		return nil
	}

	return value
}

func getKafkaClientId(clientIdPrefix string, kafkaTopics []string) string {
	if len(kafkaTopics) == 1 {
		return clientIdPrefix + "-" + kafkaTopics[0]
	}

	for _, topic := range kafkaTopics {
		parts := strings.Split(topic, ".")

		if len(parts) == 0 {
			continue
		}

		lastPart := parts[len(parts)-1]

		if lddRegex.MatchString(lastPart) {
			return clientIdPrefix + "-" + lastPart
		}
	}

	return clientIdPrefix
}

func main() {
	defer log.Flush()
	defer startUp.Close()
	<-startUp.Done()
}
