How can I start profiling of the entire application as soon as it starts, and then add a way to take regular snapshots.


I can help you modify your code to enable continuous profiling from startup and add regular snapshots. Here's how you can implement this:

1. First, create a new file for the continuous profiler service:

```go
// internal/pkg/profiling/continuous_profiler.go

package profiling

import (
    "fmt"
    "os"
    "path/filepath"
    "runtime"
    "runtime/pprof"
    "sync"
    "time"

    "airwatch/uem/gumdrop-ingestion/pkg/log"
)

type ContinuousProfiler struct {
    tempFolderPath    string
    snapshotInterval  time.Duration
    currentCPUProfile *os.File
    stopChan         chan struct{}
    wg               sync.WaitGroup
    logContext       *log.Context
}

func NewContinuousProfiler(tempFolderPath string, snapshotInterval time.Duration, logContext *log.Context) *ContinuousProfiler {
    return &ContinuousProfiler{
        tempFolderPath:   tempFolderPath,
        snapshotInterval: snapshotInterval,
        stopChan:        make(chan struct{}),
        logContext:      logContext,
    }
}

func (p *ContinuousProfiler) Start() error {
    // Ensure temp directory exists
    if err := os.MkdirAll(p.tempFolderPath, 0755); err != nil {
        return fmt.Errorf("failed to create temp directory: %w", err)
    }

    // Start continuous CPU profile
    cpuFileName := filepath.Join(p.tempFolderPath, fmt.Sprintf("cpu_continuous_%s.pprof", time.Now().Format("20060102_150405")))
    cpuFile, err := os.Create(cpuFileName)
    if err != nil {
        return fmt.Errorf("could not create CPU profile: %w", err)
    }

    p.currentCPUProfile = cpuFile
    if err := pprof.StartCPUProfile(cpuFile); err != nil {
        cpuFile.Close()
        return fmt.Errorf("could not start CPU profile: %w", err)
    }

    // Start goroutine for periodic memory snapshots
    p.wg.Add(1)
    go p.periodicMemorySnapshot()

    log.Infof(p.logContext, "Continuous profiling started. CPU profile: %s", cpuFileName)
    return nil
}

func (p *ContinuousProfiler) Stop() {
    close(p.stopChan)
    p.wg.Wait()

    if p.currentCPUProfile != nil {
        pprof.StopCPUProfile()
        p.currentCPUProfile.Close()
    }

    // Take one final snapshot
    p.takeMemorySnapshot()
}

func (p *ContinuousProfiler) periodicMemorySnapshot() {
    defer p.wg.Done()

    ticker := time.NewTicker(p.snapshotInterval)
    defer ticker.Stop()

    for {
        select {
        case <-ticker.C:
            p.takeMemorySnapshot()
        case <-p.stopChan:
            return
        }
    }
}

func (p *ContinuousProfiler) takeMemorySnapshot() {
    memFileName := filepath.Join(p.tempFolderPath, fmt.Sprintf("mem_snapshot_%s.pprof", time.Now().Format("20060102_150405")))
    f, err := os.Create(memFileName)
    if err != nil {
        log.Errorw(p.logContext, "Could not create memory profile", log.ErrorKey, err)
        return
    }
    defer f.Close()

    runtime.GC() // get up-to-date statistics
    if err := pprof.WriteHeapProfile(f); err != nil {
        log.Errorw(p.logContext, "Could not write memory profile", log.ErrorKey, err)
        return
    }

    log.Infof(p.logContext, "Memory snapshot written to: %s", memFileName)
}
